  "inlineSchema": "// =====================================================\n// schema.prisma — Modelo de Dados do SENAI-CIC\n// Sistema de Gestão de Desempenho e Soft Skills\n// =====================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ---- ENUM: Papéis de Acesso dos Usuários ----\nenum Role {\n  ADMIN // Acesso total ao sistema\n  COLABORADOR // Acesso apenas ao próprio perfil\n}\n\n// ---- ENUM: Níveis de Avaliação Padronizados ----\n// Seguem obrigatoriamente a escala de 1 a 4 definida pelo negócio\nenum NivelAvaliacao {\n  CRITICO // 1 - Vermelho\n  EM_DESENVOLVIMENTO // 2 - Amarelo\n  ATINGIU // 3 - Verde\n  EXCEDEU // 4 - Azul\n}\n\n// ---- TABELA: Equipes ----\nmodel Equipe {\n  id        Int      @id @default(autoincrement())\n  nome      String   @unique\n  descricao String?\n  criadoEm  DateTime @default(now())\n\n  // Relação: uma equipe tem vários usuários\n  usuarios Usuario[]\n}\n\n// ---- TABELA: Usuários ----\n// Centraliza tanto admins quanto colaboradores\nmodel Usuario {\n  id           Int      @id @default(autoincrement())\n  nome         String\n  email        String   @unique\n  senhaHash    String // Senha armazenada como hash bcrypt (NUNCA texto puro)\n  cargo        String? // Ex: \"Instrutor\", \"Supervisor\"\n  papel        Role     @default(COLABORADOR)\n  ativo        Boolean  @default(true)\n  criadoEm     DateTime @default(now())\n  atualizadoEm DateTime @updatedAt\n\n  // Relação com equipe (opcional — usuário pode não estar em equipe ainda)\n  equipeId Int?\n  equipe   Equipe? @relation(fields: [equipeId], references: [id])\n\n  // Relações N:N com avaliações:\n  // Um usuário pode ter FEITO muitas avaliações (como avaliador)\n  avaliacoesFeitas    Avaliacao[] @relation(\"Avaliador\")\n  // Um usuário pode ter RECEBIDO muitas avaliações (como avaliado)\n  avaliacoesRecebidas Avaliacao[] @relation(\"Avaliado\")\n}\n\n// ---- TABELA: Ciclos de Avaliação ----\n// Representa um período de avaliação (ex: \"Q1 2024 - Jan a Mar\")\nmodel CicloAvaliacao {\n  id          Int      @id @default(autoincrement())\n  nome        String\n  dataInicio  DateTime\n  dataFim     DateTime\n  tipoPeriodo String   @default(\"MENSAL\") // Ex: \"MENSAL\", \"TRIMESTRAL\", \"SEMESTRAL\"\n  // Ciclos fechados NÃO podem ser editados (regra de negócio crítica)\n  fechado     Boolean  @default(false)\n  criadoEm    DateTime @default(now())\n\n  // Um ciclo contém várias avaliações\n  avaliacoes Avaliacao[]\n}\n\n// ---- TABELA: Competências / Soft Skills ----\n// Catálogo de habilidades que podem ser avaliadas\nmodel Competencia {\n  id        Int     @id @default(autoincrement())\n  nome      String  @unique // Ex: \"Trabalho em Equipe\", \"Comunicação\"\n  descricao String?\n  categoria String? // Ex: \"Interpessoal\", \"Liderança\"\n  ativo     Boolean @default(true)\n\n  // Uma competência pode aparecer em muitas avaliações\n  avaliacoes Avaliacao[]\n}\n\n// ---- ENUM: Tipos de Avaliação ----\nenum TipoAvaliacao {\n  AUTO // Autoavaliação\n  LIDER // Avaliação da Liderança\n  PAR // Avaliação 360° (Colega)\n}\n\n// ---- TABELA: Avaliações (Tabela de Junção N:N) ----\n// Esta tabela implementa a relação N:N entre Usuários:\n//   - Um usuário (avaliador) avalia MUITOS outros (avaliados)\n//   - Um usuário (avaliado) é avaliado por MUITOS outros (avaliadores)\n// A combinação avaliadorId + avaliadoId + cicloId + competenciaId + tipo deve ser única\nmodel Avaliacao {\n  id           Int            @id @default(autoincrement())\n  pontuacao    Int // Valor numérico: agora de 1 a 10\n  nivel        NivelAvaliacao // Nível padronizado correspondente à pontuação\n  tipo         TipoAvaliacao  @default(PAR)\n  anonimo      Boolean        @default(true) // Flag para definir se a avaliação é anônima\n  observacoes  String? // Comentário opcional do avaliador (anônimo no frontend)\n  criadoEm     DateTime       @default(now())\n  atualizadoEm DateTime       @updatedAt\n\n  // Relação com o avaliador (quem fez a avaliação)\n  // O frontend 360° NUNCA deve expor este campo para o avaliado\n  avaliadorId Int\n  avaliador   Usuario @relation(\"Avaliador\", fields: [avaliadorId], references: [id])\n\n  // Relação com o avaliado (quem recebeu a avaliação)\n  avaliadoId Int\n  avaliado   Usuario @relation(\"Avaliado\", fields: [avaliadoId], references: [id])\n\n  // Relação com o ciclo de avaliação\n  cicloId Int\n  ciclo   CicloAvaliacao @relation(fields: [cicloId], references: [id])\n\n  // Relação com a competência avaliada\n  competenciaId Int\n  competencia   Competencia @relation(fields: [competenciaId], references: [id])\n\n  // Garante que um avaliador só possa avaliar a mesma competência\n  // de um avaliado uma única vez por ciclo por tipo\n  @@unique([avaliadorId, avaliadoId, cicloId, competenciaId, tipo])\n  @@index([avaliadoId, cicloId]) // Índice para acelerar buscas do dashboard\n}\n",
